using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ── CalculateTotal: DataRow-driven tests ────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 10, 0.20, 0.00, DisplayName = "Zero unit price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    [DataRow(100.00, 2, 1.0, 400.00, DisplayName = "Maximum tax rate (100%)")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── CalculateTotal: DynamicData for complex / edge cases ────────────

    public static IEnumerable<object[]> CalculateTotalEdgeCases
    {
        get
        {
            yield return new object[] { 0.01m, 1, 0.0m, 0.01m, "Smallest meaningful price" };
            yield return new object[] { 9999.99m, 100, 0.25m, 1_249_998.75m, "Large order with tax" };
            yield return new object[] { 1.00m, 1, 0.0m, 1.00m, "Unit identity" };
            yield return new object[] { 33.33m, 3, 0.07m, 106.9893m, "Repeating decimal result" };
        }
    }

    [TestMethod]
    [DynamicData(nameof(CalculateTotalEdgeCases))]
    public void CalculateTotal_EdgeCases_ReturnsExpected(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected, string scenario)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result, $"Failed for scenario: {scenario}");
    }

    // ── CalculateTotal: invalid-input tests ─────────────────────────────

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price")]
    public void CalculateTotal_NegativeUnitPrice_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity")]
    public void CalculateTotal_NegativeQuantity_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, 1, -0.01, DisplayName = "Tax rate below 0")]
    [DataRow(10.00, 1, 1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // ── ApplyDiscount: DataRow-driven tests ─────────────────────────────

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount")]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% discount")]
    [DataRow(100.00, 50.0, 50.00, DisplayName = "50% discount")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% discount (free)")]
    [DataRow(49.99, 25.0, 37.4925, DisplayName = "Fractional result")]
    [DataRow(0.00, 50.0, 0.00, DisplayName = "Zero price, any discount")]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── ApplyDiscount: DynamicData for boundary / edge cases ────────────

    public static IEnumerable<object[]> ApplyDiscountBoundaryCases
    {
        get
        {
            yield return new object[] { 200.00m, 0.01m, 199.98m, "Tiny discount" };
            yield return new object[] { 200.00m, 99.99m, 0.02m, "Nearly-free discount" };
            yield return new object[] { 1_000_000.00m, 15.0m, 850_000.00m, "Large price" };
        }
    }

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountBoundaryCases))]
    public void ApplyDiscount_BoundaryCases_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected, string scenario)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result, $"Failed for scenario: {scenario}");
    }

    // ── ApplyDiscount: invalid-input tests ──────────────────────────────

    [TestMethod]
    [DataRow(100.00, -1.0, DisplayName = "Negative discount")]
    [DataRow(100.00, 100.01, DisplayName = "Discount exceeds 100%")]
    public void ApplyDiscount_InvalidDiscount_Throws(double price, double discountPercent)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent));
    }
}

